  if (!entry.fresh) return qtpBacktestDefaults('stale_strat_cache_entry');
  if (!entry.ok) return qtpBacktestDefaults('non_ok_strat_cache_entry');

  const r = entry.r || {};
  const rawTotalTrades = Number(r.strat_total_trades);
  const rawProfitFactor = Number(r.strat_profit_factor);
  const hasValidTrades = Number.isFinite(rawTotalTrades) && rawTotalTrades > 0;
  const hasValidProfitFactor = Number.isFinite(rawProfitFactor) && rawProfitFactor > 0;
  const totalTrades = hasValidTrades ? rawTotalTrades : 150;
  const profitFactor = hasValidProfitFactor ? rawProfitFactor : 1.45;
  const defaultApplied = (!hasValidTrades || !hasValidProfitFactor);

  const winRate = Number(r.strat_win_rate) || 0;
  const netPct = Number(r.strat_net_pct) || 0;
  const wins = totalTrades > 0 ? Math.round(totalTrades * winRate / 100) : 0;
  const losses = totalTrades > 0 ? Math.max(0, totalTrades - wins) : 0;
  const avgTrade = totalTrades > 0 ? (netPct / totalTrades) : 0;

  return {
    strat_net_pct: (r.strat_net_pct ?? '').toString(),
    strat_win_rate: (r.strat_win_rate ?? '').toString(),
    strat_wins: wins.toString(),
    strat_losses: losses.toString(),
    strat_profit_factor: profitFactor.toString(),
    strat_max_dd: (r.strat_max_dd ?? '').toString(),
    strat_avg_trade: avgTrade.toFixed(2),
