    backtest_default_applied: defaultApplied ? 'true' : 'false',
    backtest_default_reason: defaultApplied ? 'missing_or_zero_backtest_metrics' : 'none',
    backtest_sample_size: totalTrades.toString(),
    backtest_profit_factor: profitFactor.toString()
  };
