function sma(values, period) {
  if (values.length < period) return null;
  const slice = values.slice(-period);
  return slice.reduce((a, b) => a + b, 0) / period;
}
function ema(values, period) {
  if (values.length < period) return null;
  const k = 2 / (period + 1);
  let e = values.slice(0, period).reduce((a, b) => a + b, 0) / period;
  for (let i = period; i < values.length; i++) e = values[i] * k + e * (1 - k);
  return e;
}
function rsi(values, period = 14) {
  if (values.length < period + 1) return null;
  let gains = 0, losses = 0;
  for (let i = 1; i <= period; i++) {
    const d = values[i] - values[i - 1];
    if (d > 0) gains += d; else losses -= d;
  }
  let ag = gains / period, al = losses / period;
  for (let i = period + 1; i < values.length; i++) {
    const d = values[i] - values[i - 1];
    ag = (ag * (period - 1) + (d > 0 ? d : 0)) / period;
    al = (al * (period - 1) + (d < 0 ? -d : 0)) / period;
  }
  return al === 0 ? 100 : 100 - 100 / (1 + ag / al);
}
function macdHist(values) {
  if (values.length < 40) return null;
  const macdSeries = [];
  for (let i = 26; i <= values.length; i++) {
    const sub = values.slice(0, i);
    const e12 = ema(sub, 12), e26 = ema(sub, 26);
    if (e12 != null && e26 != null) macdSeries.push(e12 - e26);
  }
  const sig = ema(macdSeries, 9);
  return sig == null ? null : macdSeries[macdSeries.length - 1] - sig;
}
function clamp(x, lo, hi) { return Math.max(lo, Math.min(hi, x)); }
